        st.markdown("""
        <div class="success-box">
          <div style="font-size:36px">✅</div>
          <h3>Ata gerada com sucesso!</h3>
          <p>Clique abaixo para baixar o documento Word.</p>
        </div>""", unsafe_allow_html=True)

        st.markdown("<br>", unsafe_allow_html=True)
